import {
    tuiGetCurrentWordBounds,
    tuiGetSlicedFragment,
    tuiParseNodeAttributes,
} from '@taiga-ui/editor/utils';
import {type KeyboardShortcutCommand, mergeAttributes} from '@tiptap/core';
import {Link, type LinkOptions} from '@tiptap/extension-link';
import {Plugin, PluginKey, TextSelection} from '@tiptap/pm/state';

export const TuiLink = Link.extend<LinkOptions>({
    addAttributes() {
        return {
            ...this.parent?.(),
            ...tuiParseNodeAttributes(['download']),
        };
    },

    addCommands() {
        return {
            ...this.parent?.(),
            toggleLink:
                (attributes) =>
                ({chain, state, editor}) => {
                    {
                        const pos = state.selection.from;
                        const resolvedPos = state.doc.resolve(pos);
                        const node = resolvedPos.nodeAfter || resolvedPos.nodeBefore;
                        const isImageNode = node?.type === editor.schema.nodes.image;

                        if (isImageNode) {
                            return typeof (editor.commands as any).setImageLink ===
                                'function'
                                ? (chain() as any).setImageLink().run()
                                : false;
                        }

                        if (!tuiGetSlicedFragment(state).trim()) {
                            return false;
                        }

                        const {from, to} = tuiGetCurrentWordBounds(editor);

                        const toggleMark = chain()
                            .setTextSelection({from, to})
                            .toggleMark(this.name, attributes, {
                                extendEmptyMarkRange: true,
                            })
                            .setMeta('preventAutolink', true)
                            .setTextSelection(to);

                        return toggleMark
                            .setTextSelection({
                                from,
                                to: to - from === 1 ? to : to - 1,
                            })
                            .run();
                    }
                },
        };
    },

    renderHTML({HTMLAttributes}) {
        return [
            'a',
            mergeAttributes(HTMLAttributes, {
                target: HTMLAttributes.href?.startsWith('#') ? '_self' : '_blank',
            }),
            0,
        ];
    },

    addKeyboardShortcuts(): Record<string, KeyboardShortcutCommand> {
        return {
            'Mod-k': ({editor}) => {
                const isLink = this.editor.isActive('link');
                const editorChain = editor.chain().focus();

                const command = isLink
                    ? editorChain.unsetLink()
                    : editorChain.toggleLink({href: ''});

                return command.run();
            },
        };
    },

    addProseMirrorPlugins() {
        return [
            ...(this.parent?.() ?? []),
            new Plugin({
                key: new PluginKey('tui-link-boundary-exit'),
                appendTransaction(transactions, _oldState, newState) {
                    if (!transactions.some((transaction) => transaction.selectionSet)) {
                        return null;
                    }

                    const {selection} = newState;

                    if (!(selection instanceof TextSelection) || !selection.$cursor) {
                        return null;
                    }

                    const {$cursor} = selection;
                    const linkMark = newState.schema.marks['link'];

                    if (!linkMark) {
                        return null;
                    }

                    const linkBefore = $cursor.nodeBefore
                        ? linkMark.isInSet($cursor.nodeBefore.marks)
                        : null;

                    const linkAfter = $cursor.nodeAfter
                        ? linkMark.isInSet($cursor.nodeAfter.marks)
                        : null;

                    if (!linkBefore || linkAfter) {
                        return null;
                    }

                    const storedMarks = newState.storedMarks ?? $cursor.marks();

                    return storedMarks.some((mark) => mark.type === linkMark)
                        ? newState.tr.setStoredMarks(
                              storedMarks.filter((mark) => mark.type !== linkMark),
                          )
                        : null;
                },
            }),
        ];
    },

    addPasteRules() {
        return [
            // Workaround for issue: https://github.com/ueberdosis/tiptap/issues/5957
        ];
    },
}).configure({openOnClick: false});
